using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using VetClinic.Data.Models;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<Treatment> Treatments => Set<Treatment>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceItem> InvoiceItems => Set<InvoiceItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>().HasMany(o => o.Pets).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId);
        builder.Entity<Pet>().HasMany(p => p.Treatments).WithOne(t => t.Pet).HasForeignKey(t => t.PetId);
        builder.Entity<Pet>().HasMany(p => p.Appointments).WithOne(a => a.Pet).HasForeignKey(a => a.PetId);
        builder.Entity<Invoice>().HasMany(i => i.Items).WithOne(item => item.Invoice).HasForeignKey(item => item.InvoiceId);
        builder.Entity<Invoice>().HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId);
        builder.Entity<Invoice>().HasOne(i => i.Owner).WithMany().HasForeignKey(i => i.OwnerId);

        builder.Entity<Treatment>().Property(t => t.Cost).HasColumnType("decimal(10,2)");
        builder.Entity<Pet>().Property(p => p.WeightKg).HasColumnType("decimal(6,2)");
        builder.Entity<Invoice>().Property(i => i.TotalAmount).HasColumnType("decimal(10,2)");
        builder.Entity<InvoiceItem>().Property(i => i.UnitPrice).HasColumnType("decimal(10,2)");
        builder.Entity<Payment>().Property(p => p.Amount).HasColumnType("decimal(10,2)");
    }
}

