@page "/"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var appt in upcomingAppointments)
                    {
                        <tr>
                            <td>@appt.StartTime.ToString("g")</td>
                            <td>@appt.Pet.Name</td>
                            <td>@appt.Reason</td>
                            <td>@appt.Veterinarian</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Pet</th><th>Treatment</th></tr></thead>
                <tbody>
                    @foreach (var t in recentTreatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Pet.Name</td>
                            <td>@t.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent treatments.</p>
        }
    </div>
</div>

@code {
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<Appointment> upcomingAppointments = [];
    private List<Treatment> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.UtcNow.Date;

        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients - VetClinic</PageTitle>

<h2>Patient Management</h2>

<div class="row mb-3">
    <div class="col">
        <input class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelOwnerForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
