    </div>
}

@code {
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private string searchTerm = "";

    private bool showOwnerForm, showPetForm, showTreatmentForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Treatment editingTreatment = new();
    private Pet? selectedPet;
    private Pet? treatmentPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).Include(p => p.Treatments).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; }
    private void CancelOwnerForm() => showOwnerForm = false;

    private void ShowAddPet() { editingPet = new(); showPetForm = true; }
    private void CancelPetForm() => showPetForm = false;

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species,
            Breed = pet.Breed, DateOfBirth = pet.DateOfBirth,
            WeightKg = pet.WeightKg, OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task ViewHistory(Pet pet)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        selectedPet = await db.Pets.Include(p => p.Treatments).FirstOrDefaultAsync(p => p.Id == pet.Id);
    }

    private void ShowTreatmentForm(Pet pet)
    {
        treatmentPet = pet;
        editingTreatment = new Treatment { PetId = pet.Id, Date = DateTime.UtcNow };
        showTreatmentForm = true;
    }

    private void EditTreatment(Treatment t)
    {
        treatmentPet = selectedPet;
        editingTreatment = new Treatment
        {
            Id = t.Id, PetId = t.PetId, Date = t.Date,
            Description = t.Description, Notes = t.Notes,
            Veterinarian = t.Veterinarian, Cost = t.Cost
        };
        showTreatmentForm = true;
    }

    private void CancelTreatmentForm() => showTreatmentForm = false;

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0)
            db.Owners.Add(editingOwner);
        else
            db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0)
            db.Pets.Add(editingPet);
        else
            db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task SaveTreatment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingTreatment.Id == 0)
            db.Treatments.Add(editingTreatment);
        else
            db.Treatments.Update(editingTreatment);
        await db.SaveChangesAsync();
        showTreatmentForm = false;
        await LoadData();
        if (selectedPet != null)
            selectedPet = await db.Pets.Include(p => p.Treatments).FirstOrDefaultAsync(p => p.Id == selectedPet.Id);
    }
}

@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments - VetClinic</PageTitle>

<h2>Appointment Scheduling</h2>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="viewDate" @bind:event="onchange" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Start Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">End Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.EndTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        <ValidationMessage For="() => editingAppointment.Reason" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                @if (conflictMessage != null)
                {
                    <div class="alert alert-warning mt-2">@conflictMessage</div>
                }
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @viewDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    var appt = GetAppointmentAt(slot);
                    <tr class="@(appt != null ? "table-info" : "")">
                        <td>@slot.ToString("HH:mm")</td>
                        @if (appt != null)
                        {
                            <td>@appt.Pet.Name</td>
                            <td>@appt.Reason</td>
                            <td>@appt.Veterinarian</td>
                            <td><span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span></td>
                            <td>
                                @if (appt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(appt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(appt)">Cancel</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(appt)">Complete</button>
                                }
                            </td>
                        }
                        else
                        {
                            <td colspan="4" class="text-muted">Available</td>
                            <td>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => QuickBook(slot)">Book</button>
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Real-Time Availability</div>
            <div class="card-body">
                <p><strong>Total Slots:</strong> @timeSlots.Count</p>
                <p><strong>Booked:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled)</p>
                <p><strong>Available:</strong> @(timeSlots.Count - dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled))</p>
                <div class="progress">
                    @{ var pct = timeSlots.Count > 0 ? (int)(100.0 * dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled) / timeSlots.Count) : 0; }
                    <div class="progress-bar" style="width: @(pct)%">@pct%</div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private DateOnly viewDate = DateOnly.FromDateTime(DateTime.Today);
    private List<Pet> pets = [];
    private List<Appointment> dayAppointments = [];
    private List<DateTime> timeSlots = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private string? conflictMessage;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadDayAppointments();
    }

    private async Task LoadDayAppointments()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var start = viewDate.ToDateTime(TimeOnly.MinValue);
        var end = viewDate.ToDateTime(TimeOnly.MaxValue);
        dayAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= start && a.StartTime <= end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        // Generate 30-min slots from 8:00 to 18:00
        timeSlots = [];
        for (var hour = 8; hour < 18; hour++)
        {
            timeSlots.Add(viewDate.ToDateTime(new TimeOnly(hour, 0)));
            timeSlots.Add(viewDate.ToDateTime(new TimeOnly(hour, 30)));
        }
    }

    private Appointment? GetAppointmentAt(DateTime slot)
        => dayAppointments.FirstOrDefault(a => a.StartTime <= slot && a.EndTime > slot && a.Status != AppointmentStatus.Cancelled);

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment
        {
            StartTime = viewDate.ToDateTime(new TimeOnly(9, 0)),
            EndTime = viewDate.ToDateTime(new TimeOnly(9, 30))
        };
        conflictMessage = null;
        showForm = true;
    }

    private void QuickBook(DateTime slot)
    {
        editingAppointment = new Appointment
        {
            StartTime = slot,
            EndTime = slot.AddMinutes(30)
        };
        conflictMessage = null;
        showForm = true;
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = new Appointment
        {
            Id = appt.Id, PetId = appt.PetId, StartTime = appt.StartTime,
            EndTime = appt.EndTime, Reason = appt.Reason, Notes = appt.Notes,
            Veterinarian = appt.Veterinarian, Status = appt.Status
        };
        conflictMessage = null;
        showForm = true;
    }

    private void CancelForm() { showForm = false; conflictMessage = null; }

    private async Task SaveAppointment()
    {
        using var db = await DbFactory.CreateDbContextAsync();

        // Check for conflicts
        var hasConflict = await db.Appointments.AnyAsync(a =>
            a.Id != editingAppointment.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.Veterinarian == editingAppointment.Veterinarian &&
            a.StartTime < editingAppointment.EndTime &&
            a.EndTime > editingAppointment.StartTime);

        if (hasConflict)
        {
            conflictMessage = "Time conflict detected for this veterinarian. Please choose a different time.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        conflictMessage = null;
        await LoadDayAppointments();
    }

    private async Task Cancel(Appointment appt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadDayAppointments();
    }

    private async Task Complete(Appointment appt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadDayAppointments();
    }

    private static string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

