@code {
    private string activeTab = "invoices";
    private List<Owner> owners = [];
    private List<Invoice> invoices = [];
    private List<Payment> payments = [];

    private bool showInvoiceForm, showPaymentForm;
    private Invoice editingInvoice = new();
    private List<InvoiceItem> invoiceItems = [];
    private Payment editingPayment = new();
    private Invoice? paymentInvoice;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    private void ShowNewInvoice()
    {
        editingInvoice = new Invoice { DueDate = DateTime.UtcNow.AddDays(30) };
        invoiceItems = [new InvoiceItem()];
        showInvoiceForm = true;
    }

    private void CancelInvoiceForm() => showInvoiceForm = false;
    private void AddLineItem() => invoiceItems.Add(new InvoiceItem());

    private async Task SaveInvoice()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        editingInvoice.TotalAmount = invoiceItems.Sum(i => i.Quantity * i.UnitPrice);
        editingInvoice.Items = invoiceItems;
        db.Invoices.Add(editingInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        paymentInvoice = inv;
        editingPayment = new Payment { InvoiceId = inv.Id, Amount = inv.Balance };
        showPaymentForm = true;
    }

    private void CancelPaymentForm() => showPaymentForm = false;

    private async Task ProcessPayment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(editingPayment);
        await db.SaveChangesAsync();

        // Update invoice status
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == editingPayment.InvoiceId);
        var totalPaid = invoice.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        invoice.Status = totalPaid >= invoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Invoices.FindAsync(inv.Id);
        if (entity != null)
        {
            entity.Status = InvoiceStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private static string GetInvoiceStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}

