                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingTreatment.Veterinarian" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingTreatment.Date" />
