{"file_text": "@page "/billing"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Billing - VetClinic</PageTitle>

<h2>Billing & Payments</h2>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3">
            <div class="card-header">New Invoice</div>
            <div class="card-body">
                <EditForm Model="editingInvoice" OnValidSubmit="SaveInvoice" FormName="invoiceForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-3">
                            <label class="form-label">Owner</label>
                            <InputSelect class="form-select" @bind-Value="editingInvoice.OwnerId">
                                <option value="0">-- Select Owner --</option>
                                @foreach (var o in owners)
                                {
                                    <option value="@o.Id">@o.FullName</option>
                                }
                            </InputSelect>
                        </div>
                        <div class="col-md-3">
                            <label class="form-label">Description</label>
                            <InputText class="form-control" @bind-Value="editingInvoice.Description" />
                        </div>
                        <div class="col-md-3">
                            <label class="form-label">Due Date</label>
                            <InputDate class="form-control" @bind-Value="editingInvoice.DueDate" />
                        </div>
                    </div>

                    <h5 class="mt-3">Line Items</h5>
                    @for (int i = 0; i < invoiceItems.Count; i++)
                    {
                        var idx = i;
                        <div class="row mb-1">
                            <div class="col-md-4">
                                <input class="form-control" placeholder="Description" @bind="invoiceItems[idx].Description" />
                            </div>
                            <div class="col-md-2">
                                <input type="number" class="form-control" placeholder="Qty" @bind="invoiceItems[idx].Quantity" />
                            </div>
                            <div class="col-md-2">
                                <input type="number" class="form-control" step="0.01" placeholder="Unit Price" @bind="invoiceItems[idx].UnitPrice" />
                            </div>
                            <div class="col-md-2">
                                <span class="form-control-plaintext">@((invoiceItems[idx].Quantity * invoiceItems[idx].UnitPrice).ToString("C"))</span>
                            </div>
                            <div class="col-md-2">
                                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => invoiceItems.RemoveAt(idx)">Remove</button>
                            </div>
                        </div>
                    }
                    <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="AddLineItem">+ Add Item</button>
                    <div class="mt-2"><strong>Total: @invoiceItems.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</strong></div>

                    <button type="submit" class="btn btn-primary mt-2">Create Invoice</button>
                    <button type="button" class="btn btn-secondary mt-2" @onclick="CancelInvoiceForm">Cancel</button>
                </EditForm>
            </div>
        </div>
    }

    <table class="table table-hover">
        <thead>
            <tr><th>#</th><th>Owner</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.Owner.FullName</td>
                    <td>@inv.Description</td>
                    <td>@inv.TotalAmount.ToString("C")</td>
                    <td>@inv.AmountPaid.ToString("C")</td>
                    <td>@inv.Balance.ToString("C")</td>
                    <td><span class="badge bg-@GetInvoiceStatusColor(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status == InvoiceStatus.Pending || inv.Status == InvoiceStatus.PartiallyPaid)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Pay</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelInvoice(inv)">Cancel</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (activeTab == "payments")
{
    <table class="table table-hover">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Reference</th><th>Status</th></tr>
        </thead>
        <tbody>
            @foreach (var pay in payments)
            {
                <tr>
                    <td>@pay.Date.ToString("g")</td>
                    <td>@pay.InvoiceId</td>
                    <td>@pay.Invoice.Owner.FullName</td>
                    <td>@pay.Amount.ToString("C")</td>
                    <td>@pay.Method</td>
                    <td>@pay.Reference</td>
                    <td><span class="badge bg-@(pay.Status == PaymentStatus.Completed ? "success" : "warning")">@pay.Status</span></td>
                </tr>
            }
        </tbody>
    </table>
}

@if (showPaymentForm)
{
    <div class="card mt-3">
        <div class="card-header">Process Payment — Invoice #@paymentInvoice!.Id (Balance: @paymentInvoice.Balance.ToString("C"))</div>
        <div class="card-body">
            <EditForm Model="editingPayment" OnValidSubmit="ProcessPayment" FormName="paymentForm">
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Amount</label>
                        <InputNumber class="form-control" @bind-Value="editingPayment.Amount" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Method</label>
                        <InputSelect class="form-select" @bind-Value="editingPayment.Method">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reference</label>
                        <InputText class="form-control" @bind-Value="editingPayment.Reference" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Process Payment</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelPaymentForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private List<Owner> owners = [];
    private List<Invoice> invoices = [];
    private List<Payment> payments = [];

    private bool showInvoiceForm, showPaymentForm;
    private Invoice editingInvoice = new();
    private List<InvoiceItem> invoiceItems = [];
    private Payment editingPayment = new();
    private Invoice? paymentInvoice;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
        invoices = await db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.CreatedDate)
            .ToListAsync();
        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .ToListAsync();
    }

    private void ShowNewInvoice()
    {
        editingInvoice = new Invoice { DueDate = DateTime.UtcNow.AddDays(30) };
        invoiceItems = [new InvoiceItem()];
        showInvoiceForm = true;
    }

    private void CancelInvoiceForm() => showInvoiceForm = false;
    private void AddLineItem() => invoiceItems.Add(new InvoiceItem());

    private async Task SaveInvoice()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        editingInvoice.TotalAmount = invoiceItems.Sum(i => i.Quantity * i.UnitPrice);
        editingInvoice.Items = invoiceItems;
        db.Invoices.Add(editingInvoice);
        await db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPaymentForm(Invoice inv)
    {
        paymentInvoice = inv;
        editingPayment = new Payment { InvoiceId = inv.Id, Amount = inv.Balance };
        showPaymentForm = true;
    }

    private void CancelPaymentForm() => showPaymentForm = false;

    private async Task ProcessPayment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        db.Payments.Add(editingPayment);
        await db.SaveChangesAsync();

        // Update invoice status
        var invoice = await db.Invoices.Include(i => i.Payments).FirstAsync(i => i.Id == editingPayment.InvoiceId);
        var totalPaid = invoice.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        invoice.Status = totalPaid >= invoice.TotalAmount ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;
        await db.SaveChangesAsync();

        showPaymentForm = false;
        await LoadData();
    }

    private async Task CancelInvoice(Invoice inv)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Invoices.FindAsync(inv.Id);
        if (entity != null)
        {
            entity.Status = InvoiceStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadData();
    }

    private static string GetInvoiceStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Cancelled => "danger",
        _ => "secondary"
    };
}
