@page "/"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var appt in upcomingAppointments)
                    {
                        <tr>
                            <td>@appt.StartTime.ToString("g")</td>
                            <td>@appt.Pet.Name</td>
                            <td>@appt.Reason</td>
                            <td>@appt.Veterinarian</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Pet</th><th>Treatment</th></tr></thead>
                <tbody>
                    @foreach (var t in recentTreatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Pet.Name</td>
                            <td>@t.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent treatments.</p>
        }
    </div>
</div>

@code {
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<Appointment> upcomingAppointments = [];
    private List<Treatment> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.UtcNow.Date;

        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

@page "/patients"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Patients - VetClinic</PageTitle>

<h2>Patient Management</h2>

<div class="row mb-3">
    <div class="col">
        <input class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowAddOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowAddPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                        <ValidationMessage For="() => editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                        <ValidationMessage For="() => editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelOwnerForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                        <ValidationMessage For="() => editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="editingPet.Species" />
                        <ValidationMessage For="() => editingPet.Species" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.WeightKg" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">-- Select --</option>
                            @foreach (var o in owners)
                            {
                                <option value="@o.Id">@o.FullName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelPetForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in FilteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@pet.Owner.FullName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <button class="btn btn-sm btn-outline-info" @onclick="() => ViewHistory(pet)">History</button>
                    <button class="btn btn-sm btn-outline-success" @onclick="() => ShowTreatmentForm(pet)">+ Treatment</button>
                </td>
            </tr>
        }
    </tbody>
</table>

@if (selectedPet != null)
{
    <div class="card mt-3">
        <div class="card-header">Medical History — @selectedPet.Name</div>
        <div class="card-body">
            @if (selectedPet.Treatments.Any())
            {
                <table class="table table-sm">
                    <thead><tr><th>Date</th><th>Description</th><th>Notes</th><th>Vet</th><th>Cost</th><th></th></tr></thead>
                    <tbody>
                        @foreach (var t in selectedPet.Treatments.OrderByDescending(t => t.Date))
                        {
                            <tr>
                                <td>@t.Date.ToString("d")</td>
                                <td>@t.Description</td>
                                <td>@t.Notes</td>
                                <td>@t.Veterinarian</td>
                                <td>@t.Cost.ToString("C")</td>
                                <td><button class="btn btn-sm btn-outline-warning" @onclick="() => EditTreatment(t)">Edit</button></td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No treatment records.</p>
            }
            <button class="btn btn-sm btn-secondary" @onclick="() => selectedPet = null">Close</button>
        </div>
    </div>
}

@if (showTreatmentForm)
{
    <div class="card mt-3">
        <div class="card-header">@(editingTreatment.Id == 0 ? "Add Treatment" : "Edit Treatment") — @treatmentPet!.Name</div>
        <div class="card-body">
            <EditForm Model="editingTreatment" OnValidSubmit="SaveTreatment" FormName="treatmentForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Description</label>
                        <InputText class="form-control" @bind-Value="editingTreatment.Description" />
                        <ValidationMessage For="() => editingTreatment.Description" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingTreatment.Notes" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingTreatment.Veterinarian" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingTreatment.Date" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Cost</label>
                        <InputNumber class="form-control" @bind-Value="editingTreatment.Cost" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelTreatmentForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private List<Pet> pets = [];
    private List<Owner> owners = [];
    private string searchTerm = "";

    private bool showOwnerForm, showPetForm, showTreatmentForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();
    private Treatment editingTreatment = new();
    private Pet? selectedPet;
    private Pet? treatmentPet;

    private IEnumerable<Pet> FilteredPets => string.IsNullOrWhiteSpace(searchTerm)
        ? pets
        : pets.Where(p =>
            p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Owner.FullName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).Include(p => p.Treatments).OrderBy(p => p.Name).ToListAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void ShowAddOwner() { editingOwner = new(); showOwnerForm = true; }
    private void CancelOwnerForm() => showOwnerForm = false;

    private void ShowAddPet() { editingPet = new(); showPetForm = true; }
    private void CancelPetForm() => showPetForm = false;

    private void EditPet(Pet pet)
    {
        editingPet = new Pet
        {
            Id = pet.Id, Name = pet.Name, Species = pet.Species,
            Breed = pet.Breed, DateOfBirth = pet.DateOfBirth,
            WeightKg = pet.WeightKg, OwnerId = pet.OwnerId
        };
        showPetForm = true;
    }

    private async Task ViewHistory(Pet pet)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        selectedPet = await db.Pets.Include(p => p.Treatments).FirstOrDefaultAsync(p => p.Id == pet.Id);
    }

    private void ShowTreatmentForm(Pet pet)
    {
        treatmentPet = pet;
        editingTreatment = new Treatment { PetId = pet.Id, Date = DateTime.UtcNow };
        showTreatmentForm = true;
    }

    private void EditTreatment(Treatment t)
    {
        treatmentPet = selectedPet;
        editingTreatment = new Treatment
        {
            Id = t.Id, PetId = t.PetId, Date = t.Date,
            Description = t.Description, Notes = t.Notes,
            Veterinarian = t.Veterinarian, Cost = t.Cost
        };
        showTreatmentForm = true;
    }

    private void CancelTreatmentForm() => showTreatmentForm = false;

    private async Task SaveOwner()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingOwner.Id == 0)
            db.Owners.Add(editingOwner);
        else
            db.Owners.Update(editingOwner);
        await db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingPet.Id == 0)
            db.Pets.Add(editingPet);
        else
            db.Pets.Update(editingPet);
        await db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private async Task SaveTreatment()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        if (editingTreatment.Id == 0)
            db.Treatments.Add(editingTreatment);
        else
            db.Treatments.Update(editingTreatment);
        await db.SaveChangesAsync();
        showTreatmentForm = false;
        await LoadData();
        if (selectedPet != null)
            selectedPet = await db.Pets.Include(p => p.Treatments).FirstOrDefaultAsync(p => p.Id == selectedPet.Id);
    }
}

@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.EntityFrameworkCore
@inject IDbContextFactory<ApplicationDbContext> DbFactory

<PageTitle>Appointments - VetClinic</PageTitle>

<h2>Appointment Scheduling</h2>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="viewDate" @bind:event="onchange" />
    </div>
    <div class="col-md-3 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointment">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingAppointment.Id == 0 ? "New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.PetId">
                            <option value="0">-- Select Pet --</option>
                            @foreach (var p in pets)
                            {
                                <option value="@p.Id">@p.Name (@p.Owner.FullName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Start Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.StartTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">End Time</label>
                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="editingAppointment.EndTime" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Veterinarian" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                        <ValidationMessage For="() => editingAppointment.Reason" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                @if (conflictMessage != null)
                {
                    <div class="alert alert-warning mt-2">@conflictMessage</div>
                }
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @viewDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    var appt = GetAppointmentAt(slot);
                    <tr class="@(appt != null ? "table-info" : "")">
                        <td>@slot.ToString("HH:mm")</td>
                        @if (appt != null)
                        {
                            <td>@appt.Pet.Name</td>
                            <td>@appt.Reason</td>
                            <td>@appt.Veterinarian</td>
                            <td><span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span></td>
                            <td>
                                @if (appt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-primary" @onclick="() => Reschedule(appt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(appt)">Cancel</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(appt)">Complete</button>
                                }
                            </td>
                        }
                        else
                        {
                            <td colspan="4" class="text-muted">Available</td>
                            <td>
                                <button class="btn btn-sm btn-outline-success" @onclick="() => QuickBook(slot)">Book</button>
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Real-Time Availability</div>
            <div class="card-body">
                <p><strong>Total Slots:</strong> @timeSlots.Count</p>
                <p><strong>Booked:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled)</p>
                <p><strong>Available:</strong> @(timeSlots.Count - dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled))</p>
                <div class="progress">
                    @{ var pct = timeSlots.Count > 0 ? (int)(100.0 * dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled) / timeSlots.Count) : 0; }
                    <div class="progress-bar" style="width: @(pct)%">@pct%</div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private DateOnly viewDate = DateOnly.FromDateTime(DateTime.Today);
    private List<Pet> pets = [];
    private List<Appointment> dayAppointments = [];
    private List<DateTime> timeSlots = [];
    private bool showForm;
    private Appointment editingAppointment = new();
    private string? conflictMessage;

    protected override async Task OnInitializedAsync() => await LoadData();

    private async Task LoadData()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadDayAppointments();
    }

    private async Task LoadDayAppointments()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var start = viewDate.ToDateTime(TimeOnly.MinValue);
        var end = viewDate.ToDateTime(TimeOnly.MaxValue);
        dayAppointments = await db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= start && a.StartTime <= end && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        // Generate 30-min slots from 8:00 to 18:00
        timeSlots = [];
        for (var hour = 8; hour < 18; hour++)
        {
            timeSlots.Add(viewDate.ToDateTime(new TimeOnly(hour, 0)));
            timeSlots.Add(viewDate.ToDateTime(new TimeOnly(hour, 30)));
        }
    }

    private Appointment? GetAppointmentAt(DateTime slot)
        => dayAppointments.FirstOrDefault(a => a.StartTime <= slot && a.EndTime > slot && a.Status != AppointmentStatus.Cancelled);

    private void ShowNewAppointment()
    {
        editingAppointment = new Appointment
        {
            StartTime = viewDate.ToDateTime(new TimeOnly(9, 0)),
            EndTime = viewDate.ToDateTime(new TimeOnly(9, 30))
        };
        conflictMessage = null;
        showForm = true;
    }

    private void QuickBook(DateTime slot)
    {
        editingAppointment = new Appointment
        {
            StartTime = slot,
            EndTime = slot.AddMinutes(30)
        };
        conflictMessage = null;
        showForm = true;
    }

    private void Reschedule(Appointment appt)
    {
        editingAppointment = new Appointment
        {
            Id = appt.Id, PetId = appt.PetId, StartTime = appt.StartTime,
            EndTime = appt.EndTime, Reason = appt.Reason, Notes = appt.Notes,
            Veterinarian = appt.Veterinarian, Status = appt.Status
        };
        conflictMessage = null;
        showForm = true;
    }

    private void CancelForm() { showForm = false; conflictMessage = null; }

    private async Task SaveAppointment()
    {
        using var db = await DbFactory.CreateDbContextAsync();

        // Check for conflicts
        var hasConflict = await db.Appointments.AnyAsync(a =>
            a.Id != editingAppointment.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.Veterinarian == editingAppointment.Veterinarian &&
            a.StartTime < editingAppointment.EndTime &&
            a.EndTime > editingAppointment.StartTime);

        if (hasConflict)
        {
            conflictMessage = "Time conflict detected for this veterinarian. Please choose a different time.";
            return;
        }

        if (editingAppointment.Id == 0)
            db.Appointments.Add(editingAppointment);
        else
            db.Appointments.Update(editingAppointment);

        await db.SaveChangesAsync();
        showForm = false;
        conflictMessage = null;
        await LoadDayAppointments();
    }

    private async Task Cancel(Appointment appt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
        await LoadDayAppointments();
    }

    private async Task Complete(Appointment appt)
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(appt.Id);
        if (entity != null)
        {
            entity.Status = AppointmentStatus.Completed;
            await db.SaveChangesAsync();
        }
        await LoadDayAppointments();
    }

    private static string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
