+    private async Task LoadDayAppointments()
+    {
+        using var db = await DbFactory.CreateDbContextAsync();
+        var start = viewDate.ToDateTime(TimeOnly.MinValue);
+        var end = viewDate.ToDateTime(TimeOnly.MaxValue);
