@code {
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<Appointment> upcomingAppointments = [];
    private List<Treatment> recentTreatments = [];

    protected override async Task OnInitializedAsync()
    {
        using var db = await DbFactory.CreateDbContextAsync();
        var today = DateTime.UtcNow.Date;

        petCount = await db.Pets.CountAsync();
        ownerCount = await db.Owners.CountAsync();
        todayAppointments = await db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid);

        upcomingAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();

        recentTreatments = await db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
}

