1. using Microsoft.AspNetCore.Components.Authorization;
2. using Microsoft.AspNetCore.Identity;
3. using Microsoft.EntityFrameworkCore;
4. using VetClinic.Components;
5. using VetClinic.Components.Account;
6. using VetClinic.Data;
7. 
8. var builder = WebApplication.CreateBuilder(args);
9. 
10. // Add services to the container.
11. builder.Services.AddRazorComponents()
12.     .AddInteractiveServerComponents();
13. 
14. builder.Services.AddCascadingAuthenticationState();
15. builder.Services.AddScoped<IdentityRedirectManager>();
16. builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();
17. 
18. builder.Services.AddAuthentication(options =>
19.     {
20.         options.DefaultScheme = IdentityConstants.ApplicationScheme;
21.         options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
22.     })
23.     .AddIdentityCookies();
24. 
25. var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
26. builder.Services.AddDbContext<ApplicationDbContext>(options =>
27.     options.UseSqlite(connectionString));
28. builder.Services.AddDbContextFactory<ApplicationDbContext>(options =>
29.     options.UseSqlite(connectionString), ServiceLifetime.Scoped);
30. builder.Services.AddDatabaseDeveloperPageExceptionFilter();
31. 
32. builder.Services.AddIdentityCore<ApplicationUser>(options =>
33.     {
34.         options.SignIn.RequireConfirmedAccount = false;
35.         options.Password.RequireNonAlphanumeric = false;
36.         options.Password.RequiredLength = 6;
37.         options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
38.     })
39.     .AddEntityFrameworkStores<ApplicationDbContext>()
40.     .AddSignInManager()
41.     .AddDefaultTokenProviders();
42. 
43. builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
44. 
45. builder.Services.AddAuthorizationBuilder()
46.     .SetFallbackPolicy(new Microsoft.AspNetCore.Authorization.AuthorizationPolicyBuilder()
47.         .RequireAuthenticatedUser()
48.         .Build());
49. 
50. var app = builder.Build();
51. 
52. // Auto-apply migrations on startup
53. using (var scope = app.Services.CreateScope())
54. {
55.     var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
56.     db.Database.Migrate();
57. }
58. 
59. // Configure the HTTP request pipeline.
60. if (app.Environment.IsDevelopment())
61. {
62.     app.UseMigrationsEndPoint();
63. }
64. else
65. {
66.     app.UseExceptionHandler("/Error", createScopeForErrors: true);
67. }
68. app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
69. app.UseAntiforgery();
70. 
71. app.MapStaticAssets();
72. app.MapRazorComponents<App>()
73.     .AddInteractiveServerRenderMode();
